    {
      "name": "multi_cloud_provisioning",
      "input": {
        "clouds": [
          {
            "cloud": "AWS",
            "resources": {
              "EC2": 1,
              "S3": 1
            }
          },
          {
            "cloud": "Azure",
            "resources": {
              "VM": 1,
              "BlobStorage": 1
            }
          }
        ]
      },
      "output": {
        "status": "success",
        "resources_created": ["EC2", "S3", "VM", "BlobStorage"]
      },
      "notes": "Tests provisioning across both AWS and Azure."
    },
    {
      "name": "invalid_terraform_configuration",
      "input": {
        "cloud": "AWS",
        "resources": {
          "EC2": -1
        }
      },
