      },
      "output": {
        "status": "success",
        "pipeline_id": "12345"
      },
      "notes": "Validates the creation of a GitLab CI/CD pipeline."
    },
    {
      "name": "gitops_workflow_deployment",
      "input": {
        "app": "my-app",
