      },
      "output": {
        "status": "success",
        "deployment_id": "67890"
      },
      "notes": "Tests deployment of an application using GitOps workflows."
    },
    {
      "name": "api_security_setup",
      "input": {
        "api": "my-api",
        "security_protocol": "OAuth 2.0"
      },
      "output": {
        "status": "success",
        "protocol": "OAuth 2.0"
      },
      "notes": "Validates the setup of API security using OAuth 2.0."
    },
    {
      "name": "observability_integration",
      "input": {
        "tool": "Grafana",
        "data_source": "Prometheus"
      },
      "output": {
        "status": "success",
        "integration": "Grafana with Prometheus"
      },
      "notes": "Tests integration of observability tools."
    },
    {
      "name": "network_security_configuration",
      "input": {
        "cloud": "Azure",
        "network_security_group": {
          "rules": [
            {
              "name": "allow_http",
              "protocol": "TCP",
              "port": 80,
              "action": "Allow"
            }
          ]
        }
      },
      "output": {
        "status": "success",
        "rules_applied": ["allow_http"]
      },
      "notes": "Validates network security group configuration."
    }
